function DomainSnake({ size = 20 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24">
      <path d="M12,3 Q17,5 18,9 Q19,14 16,17 Q13,20 10,18 Q7,16 9,13 Q11,10 14,12" fill="none" stroke="#c44040" strokeWidth="2.2" strokeLinecap="round" opacity="0.8"/>
      <circle cx="12" cy="3.5" r="1.5" fill="#c44040" opacity="0.7"/><circle cx="11.5" cy="3" r="0.6" fill="#ff6b35"/>
    </svg>
  );
}

function FireParticles({count=10}){return(
  <div className="absolute inset-0 overflow-hidden pointer-events-none" style={{borderRadius:"inherit"}}>
    {Array.from({length:count}).map((_,i)=>(
      <div key={i} className="absolute rounded-full" style={{
        left:`${8+(i*41%84)}%`,bottom:"8%",width:`${1.5+(i%4)*0.6}px`,height:`${1.5+(i%4)*0.6}px`,
        background:`radial-gradient(circle,${["#ff3300","#ff5500","#ff8800","#ffaa00"][i%4]},transparent)`,
        boxShadow:`0 0 ${2+(i%3)*2}px ${["#ff330030","#ff660030","#ffaa0030"][i%3]}`,
        animation:`pR${i%3} ${1.8+(i*.19)%2}s ${(i*.29)%3}s ease-out infinite`,opacity:0,
      }}/>
    ))}
  </div>
)}

// ===== SMALL FIELD CARD =====
function SmallCard({card, onHover, onLeave, isDefense=false, previewSide="right"}){
  const w=isDefense?126:92; const h=isDefense?92:126;
  
  return(
    <div 
      onMouseEnter={(e)=>{
        const rect=e.currentTarget.getBoundingClientRect();
        onHover(card, rect, previewSide);
      }}
      onMouseLeave={onLeave}
      className="relative cursor-pointer group" 
      style={{width:`${w}px`,height:`${h}px`}}>
      <div className="absolute inset-0 rounded-lg overflow-hidden" style={{border:"2px solid rgba(196,64,64,0.35)",boxShadow:"0 4px 16px rgba(0,0,0,0.7),0 0 24px rgba(196,64,64,0.08)"}}>
        
        <div className="absolute inset-0" style={{backgroundImage:`url(${card.img})`,backgroundSize:"cover",backgroundPosition:"center 20%"}}/>
        <div className="absolute inset-0" style={{background:"radial-gradient(ellipse 95% 85% at 50% 40%,transparent 35%,rgba(0,0,0,0.35) 100%)"}}/>
        <div className="absolute bottom-0 left-0 right-0" style={{height:"35%",background:"linear-gradient(transparent,rgba(0,0,0,0.6) 50%,rgba(5,3,8,0.92) 100%)"}}/>
        
        <FireParticles count={8}/>
        
        {/* Name */}
        <div className="absolute top-0 left-0 right-0 px-2 py-1 flex items-center justify-between" style={{background:"linear-gradient(rgba(0,0,0,0.65),transparent)"}}>
          <span className="text-[9px] font-black tracking-wide truncate" style={{color:"#c44040",textShadow:"0 1px 6px rgba(0,0,0,0.9)",fontFamily:"Georgia,serif",maxWidth:`${w-30}px`}}>{card.name}</span>
          <DomainSnake size={16}/>
        </div>
        
        {/* Flying */}
        {card.isFlying&&(
          <div className="absolute top-7 right-0.5 p-1 rounded-full" style={{background:"rgba(0,0,0,0.45)"}}>
            <Wings size={22} animated/>
          </div>
        )}
        
        {/* Position */}
        <div className="absolute right-1" style={{bottom:"28px"}}>
          <div className="w-6 h-6 rounded-md flex items-center justify-center text-[10px] font-black" style={{
            background:isDefense?"rgba(59,130,246,0.2)":"rgba(239,68,68,0.2)",
            border:`1.5px solid ${isDefense?"rgba(59,130,246,0.45)":"rgba(239,68,68,0.45)"}`,
            color:isDefense?"#93c5fd":"#fca5a5",
          }}>{isDefense?"⛊":"⚔"}</div>
        </div>
        
        {/* Stats — big */}
        <div className="absolute bottom-0 left-0 right-0 flex items-center justify-between px-1.5 py-1" style={{background:"rgba(0,0,0,0.78)",backdropFilter:"blur(4px)",borderRadius:"0 0 6px 6px"}}>
          <div className="flex items-center gap-0.5">
            <CrossedAxes size={22} color="#fb923c"/>
            <span className="text-lg font-black text-orange-400" style={{textShadow:"0 0 10px rgba(251,146,60,0.3)",fontFamily:"Georgia,serif"}}>{card.atk}</span>
          </div>
          <div className="flex items-center gap-0.5">
            <span className="text-lg font-black text-sky-400" style={{textShadow:"0 0 10px rgba(96,165,250,0.3)",fontFamily:"Georgia,serif"}}>{card.def}</span>
            <OrnateShield size={22} color="#60a5fa"/>
          </div>
        </div>
      </div>
      
      <div className="absolute -inset-2 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none" style={{background:"radial-gradient(ellipse,rgba(196,64,64,0.2),transparent 70%)",filter:"blur(8px)"}}/>
    </div>
  );
}

// ===== HAND CARD — clean: art + name + symbols + stats =====
function HandCard({card, idx, total, selected, onClick, onHover, onLeave}){
  const mid=(total-1)/2;const off=idx-mid;
  const rot=selected?0:off*3;const ty=selected?-50:Math.abs(off)*5;
  
  return(
    <div 
      onClick={onClick}
      onMouseEnter={(e)=>{
        if(!selected){
          const rect=e.currentTarget.getBoundingClientRect();
          onHover(card, rect);
        }
      }}
      onMouseLeave={onLeave}
      className="relative cursor-pointer flex-shrink-0 group"
      style={{width:"100px",height:"140px",
        transform:`rotate(${rot}deg) translateY(${ty}px) ${selected?"scale(1.3) translateY(-52px)":""}`,
        transition:"all 0.4s cubic-bezier(0.34,1.56,0.64,1)",
        zIndex:selected?50:10+idx,marginLeft:idx>0?"-14px":"0"}}>
      <div className="absolute -inset-2 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" style={{background:"radial-gradient(ellipse,rgba(196,64,64,0.2),transparent 70%)",filter:"blur(6px)"}}/>
      <div className="absolute inset-0 rounded-lg overflow-hidden" style={{border:`2px solid ${selected?"rgba(196,64,64,0.6)":"rgba(196,64,64,0.2)"}`,boxShadow:selected?"0 0 30px rgba(196,64,64,0.2),0 20px 50px rgba(0,0,0,0.8)":"0 4px 16px rgba(0,0,0,0.6)",background:"#0a0406"}}>
        
        {/* Full art */}
        <div className="absolute inset-0" style={{backgroundImage:`url(${card.img})`,backgroundSize:"cover",backgroundPosition:"center 20%"}}/>
        <div className="absolute inset-0" style={{background:"radial-gradient(ellipse 95% 85% at 50% 35%,transparent 30%,rgba(0,0,0,0.35) 100%)"}}/>
        <div className="absolute bottom-0 left-0 right-0" style={{height:"32%",background:"linear-gradient(transparent,rgba(0,0,0,0.65) 50%,rgba(5,3,8,0.92) 100%)"}}/>
        
        <FireParticles count={5}/>
        
        {/* Name */}
        <div className="absolute top-0 left-0 right-0 px-1.5 py-[3px] flex items-center justify-between" style={{background:"linear-gradient(rgba(0,0,0,0.65),transparent)"}}>
          <span className="text-[8px] font-black tracking-wide truncate" style={{color:"#c44040",textShadow:"0 1px 5px rgba(0,0,0,0.9)",fontFamily:"Georgia,serif"}}>{card.name}</span>
          <DomainSnake size={13}/>
        </div>
        
        {/* Symbols only */}
        {card.isFlying&&<div className="absolute top-6 right-0.5 p-0.5 rounded-full" style={{background:"rgba(0,0,0,0.4)"}}><Wings size={16}/></div>}
        
        {/* Stats */}
        <div className="absolute bottom-0 left-0 right-0 flex items-center justify-between px-1.5 py-1" style={{background:"rgba(0,0,0,0.8)",borderRadius:"0 0 6px 6px"}}>
          <div className="flex items-center gap-0.5">
            <CrossedAxes size={16} color="#fb923c"/>
            <span className="text-[14px] font-black text-orange-400" style={{fontFamily:"Georgia,serif"}}>{card.atk}</span>
          </div>
          <div className="flex items-center gap-0.5">
            <span className="text-[14px] font-black text-sky-400" style={{fontFamily:"Georgia,serif"}}>{card.def}</span>
            <OrnateShield size={16} color="#60a5fa"/>
          </div>
        </div>
      </div>
    </div>
  );
}

// ===== SIDE PREVIEW (left or right, not blocking the card) =====
function SidePreview({card, visible, cardRect, side="right"}){
  if(!visible||!card)return null;
  
  const atkName=["WRĘCZ","ŻYWIOŁ","MAGIA","DYSTANS"][card.atkType];
  const atkColor=card.atkType===1?"#ff6b35":card.atkType===2?"#b380ff":"#d4a843";
  
  // Position: next to the hovered card, not on top of it
  const previewW = 340;
  const previewH = 520;
  const gap = 16;
  
  let posX, posY;
  if(cardRect){
    if(side==="right"){
      posX = Math.min(cardRect.right + gap, window.innerWidth - previewW - 10);
    } else {
      posX = Math.max(cardRect.left - previewW - gap, 10);
    }
    posY = Math.max(10, Math.min(cardRect.top - 40, window.innerHeight - previewH - 10));
  } else {
    posX = side==="right" ? window.innerWidth - previewW - 20 : 20;
    posY = 60;
  }
  
  return(
    <div className="fixed pointer-events-none z-50" style={{left:`${posX}px`,top:`${posY}px`,width:`${previewW}px`,height:`${previewH}px`,animation:"pvIn 0.18s ease-out forwards"}}>
      
      {/* Glow */}
      <div className="absolute -inset-4 rounded-2xl" style={{background:"radial-gradient(ellipse,rgba(196,64,64,0.15),transparent 70%)",filter:"blur(10px)"}}/>
      
      <div className="absolute inset-0 rounded-xl overflow-hidden" style={{background:"#0a0406",boxShadow:"0 0 60px rgba(196,64,64,0.12),0 20px 60px rgba(0,0,0,0.9)"}}>
        
        {/* Animated border */}
        <div className="absolute inset-0 rounded-xl" style={{padding:"2px",background:"linear-gradient(135deg,#c44040,#ff6b35,#ffaa00,#ff6b35,#c44040,#ff6b35)",backgroundSize:"300% 300%",animation:"bM 5s linear infinite",WebkitMask:"linear-gradient(#fff 0 0) content-box,linear-gradient(#fff 0 0)",WebkitMaskComposite:"xor",maskComposite:"exclude",opacity:0.4}}/>
        
        {/* ART */}
        <div className="relative overflow-hidden" style={{height:"40%",borderRadius:"10px 10px 0 0"}}>
          <div className="absolute inset-0" style={{backgroundImage:`url(${card.img})`,backgroundSize:"cover",backgroundPosition:"center 20%"}}/>
          <div className="absolute inset-0" style={{background:"radial-gradient(ellipse 85% 80% at 50% 35%,transparent 30%,rgba(10,4,6,0.45) 100%)"}}/>
          <div className="absolute bottom-0 left-0 right-0 h-16" style={{background:"linear-gradient(transparent,#0a0406)"}}/>
          <FireParticles count={20}/>
          
          {/* Domain + Name */}
          <div className="absolute top-3 left-3"><div className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg" style={{background:"rgba(0,0,0,0.55)",border:"1px solid rgba(196,64,64,0.3)",backdropFilter:"blur(6px)"}}><DomainSnake size={18}/><span className="text-[9px] font-bold tracking-widest" style={{color:"#c44040bb"}}>WELES</span></div></div>
          <div className="absolute top-3 right-3 left-28"><div className="px-3 py-2 rounded-lg text-right" style={{background:"rgba(0,0,0,0.55)",border:"1px solid rgba(196,64,64,0.2)",backdropFilter:"blur(6px)"}}><div className="font-black tracking-wider text-sm" style={{color:"#c44040",textShadow:"0 0 15px rgba(196,64,64,0.5)",fontFamily:"Georgia,serif"}}>{card.name.toUpperCase()}</div></div></div>
          
          {/* Attribute badges */}
          <div className="absolute bottom-4 left-3 flex gap-1.5 z-10">
            <div className="flex items-center gap-1.5 px-2 py-1 rounded-lg" style={{background:"rgba(0,0,0,0.6)",border:`1px solid ${atkColor}30`,backdropFilter:"blur(4px)"}}>
              <SacredFlame size={18}/><span className="text-[8px] font-bold tracking-widest" style={{color:atkColor+"cc"}}>{atkName}</span>
            </div>
            {card.isFlying&&(
              <div className="flex items-center gap-1.5 px-2 py-1 rounded-lg" style={{background:"rgba(0,0,0,0.6)",border:"1px solid rgba(56,189,248,0.2)",backdropFilter:"blur(4px)"}}>
                <Wings size={18} animated/><span className="text-[8px] font-bold tracking-widest" style={{color:"#38bdf8bb"}}>LOT</span>
              </div>
            )}
          </div>
        </div>
        
        {/* TAG + ABILITY */}
        <div className="px-5 pt-3 pb-1.5">
          <div className="flex items-center gap-2 mb-2">
            <div className="px-2.5 py-1 rounded-md" style={{background:"rgba(196,64,64,0.12)",border:"1px solid rgba(196,64,64,0.3)"}}>
              <span className="text-[10px] font-bold tracking-widest" style={{color:"#c44040cc"}}>[{card.tag}]</span>
            </div>
            <div className="h-px flex-1" style={{background:"rgba(196,64,64,0.1)"}}/>
          </div>
          <p className="text-[13px] leading-relaxed" style={{color:"rgba(235,225,215,0.9)",fontFamily:"Georgia,serif",lineHeight:"1.65"}}>
            {card.ability}
          </p>
        </div>
        
        {/* STATS */}
        <div className="px-5 mt-1.5">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2 px-3.5 py-2 rounded-xl" style={{background:"rgba(0,0,0,0.5)",border:"1.5px solid rgba(251,146,60,0.2)"}}>
              <CrossedAxes size={28} color="#fb923c"/>
              <span className="text-2xl font-black text-orange-400" style={{textShadow:"0 0 14px rgba(251,146,60,0.3)",fontFamily:"Georgia,serif"}}>{card.atk}</span>
            </div>
            <SacredFlame size={28}/>
            <div className="flex items-center gap-2 px-3.5 py-2 rounded-xl" style={{background:"rgba(0,0,0,0.5)",border:"1.5px solid rgba(96,165,250,0.2)"}}>
              <span className="text-2xl font-black text-sky-400" style={{textShadow:"0 0 14px rgba(96,165,250,0.3)",fontFamily:"Georgia,serif"}}>{card.def}</span>
              <OrnateShield size={28} color="#60a5fa"/>
            </div>
          </div>
        </div>
        
        {/* LORE — prominent, readable */}
        <div className="px-5 pt-3 pb-3">
          <div className="h-px mb-3" style={{background:"linear-gradient(90deg,transparent,rgba(196,64,64,0.12),transparent)"}}/>
          <p className="text-[13px] italic leading-relaxed" style={{
            color:"#c4956a",
            fontFamily:"Georgia,serif",
            lineHeight:"1.7",
            borderLeft:"3px solid rgba(196,140,80,0.3)",
            paddingLeft:"14px",
          }}>
            \"{card.lore}\"
          </p>
        </div>
      </div>
    </div>
  );
}

